mapper.select:
		/* adm-item-brandmanagement-sql-oracle.xml - selectBrandCodeCountInfo */
		SELECT COUNT(1)
		FROM   TADMIN_MST_ICXBRAND	
		WHERE  DELYN = 'N'

   			AND #{SEARCH_CONDITION}

/* adm-item-brandmanagement-sql-oracle.xml - selectBrandCodeInfo */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT '0' AS CHK , BRANDKEY , BRANDNM , BRCDLENGTH , CNTRYCD , (SELECT ADCDDTNM FROM TADMIN_MST_ADCD_DT WHERE ADCDHDKEY = 'COUNTRYCODE' AND LAKEY = #{slakey} AND ADCDDTKEY = CNTRYCD) AS COUNTRYNAME , ICLOC , UOMLOC , WEIGHTLOC , DCMLPOINTLOC , PRDCTDATELOC , EXPLOC , ICLENGTH , UOMLENGTH , WEIGHTLENGTH , DCMLPOINTLENGTH , PRDCTDATELENGTH , EXPLENGTH , DCMLPOINT , UOM , UOMNM , DELYN , UOMUSEYN , DCMLPOINTUSEYN , ICUSEYN , WEIGHTUSEYN , PRDCTDATEUSEYN , EXPUSEYN , FRUOM , INSERTDATE , UPDATEDATE , INSERTURKEY , UPDATEURKEY FROM TADMIN_MST_ICXBRAND
DELYN = 'N'
AND #{SEARCH_CONDITION}
ORDER BY #{colName} DESC
ORDER BY #{colName} ASC
ORDER BY BRANDKEY DESC
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

mapper.insert:
/* adm-item-brandmanagement-sql-oracle.xml - insertBrandCode */
INSERT INTO TADMIN_MST_ICXBRAND	( 
	  BRANDKEY
	, BRANDNM
	, BRCDLENGTH
	, ICLOC
	, ICLENGTH
	, UOMLOC
	, UOMLENGTH
	, WEIGHTLOC
	, WEIGHTLENGTH
	, DCMLPOINTLOC
	, DCMLPOINTLENGTH
	, PRDCTDATELOC
	, PRDCTDATELENGTH
	, EXPLOC
	, EXPLENGTH
	, DCMLPOINT
	, UOMNM
	, UOM
	, DELYN
	, UOMUSEYN
	, DCMLPOINTUSEYN
	, INSERTDATE
	, INSERTURKEY
	, UPDATEDATE
	, UPDATEURKEY
	, ICUSEYN
	, WEIGHTUSEYN
	, PRDCTDATEUSEYN
	, EXPUSEYN
	, FRUOM
) 
VALUES	(
	  CASE #{brandkey} WHEN '0' THEN '10001' ELSE (SELECT CAST(MAX(BRANDKEY) AS INTEGER) + 1 FROM TADMIN_MST_ICXBRAND) END
	, #{brandnm}
	, #{brcdlength}
	, #{icloc}
	, #{iclength}
	, #{uomloc}
	, #{uomlength}
	, #{weightloc}
	, #{weightlength}
	, #{dcmlpointloc}
	, #{dcmlpointlength}
	, #{prdctdateloc}
	, #{prdctdatelength}
	, #{exploc}
	, #{explength}
	, #{dcmlpoint}
	, #{uomnm}
	, #{uom}
	, COALESCE(#{delyn}, 'N')
	, COALESCE(#{uomuseyn}, 'N')
	, COALESCE(#{dcmlpointuseyn}, 'N')
	, #{sysdate}
	, #{surkey}
	, #{sysdate}
	, #{surkey}
	, COALESCE(#{icuseyn}, 'N')
	, COALESCE(#{weightuseyn}, 'N')
	, COALESCE(#{prdctdateuseyn}, 'N')
	, COALESCE(#{expuseyn}, 'N')
	, #{fruom}
)

mapper.update:
		/* adm-item-brandmanagement-sql-oracle.xml - updateBrandCode */
		UPDATE TADMIN_MST_ICXBRAND
		   SET BRANDNM            = #{brandnm}
		     , CNTRYCD            = #{orcountrycode}
		     , ICLOC              = #{icloc}
		     , UOMLOC             = #{uomloc}
		     , WEIGHTLOC          = #{weightloc}
		     , DCMLPOINTLOC       = #{dcmlpointloc}
		     , PRDCTDATELOC    	  = #{prdctdateloc}
		     , EXPLOC     		  = #{exploc}
		     , ICLENGTH           = #{iclength}
		     , UOMLENGTH          = #{uomlength}
		     , WEIGHTLENGTH       = #{weightlength}
		     , DCMLPOINTLENGTH    = #{dcmlpointlength}
		     , PRDCTDATELENGTH 	  = #{prdctdatelength}
		     , EXPLENGTH  		  = #{explength}
		     , BRCDLENGTH         = #{brcdlength}
		     , DCMLPOINT          = #{dcmlpoint}
		     , UOMNM              = #{uomnm}
		     , UOM				  = #{uom}
		     , DELYN              = #{delyn}
		     , UOMUSEYN           = COALESCE(#{uomuseyn}, 'Y')
			 , DCMLPOINTUSEYN     = COALESCE(#{dcmlpointuseyn}, 'Y')
		     , UPDATEURKEY        = #{surkey}
             , UPDATEDATE         = #{sysdate}
             , ICUSEYN		  	  = #{icuseyn}
			 , WEIGHTUSEYN        = #{weightuseyn}
			 , PRDCTDATEUSEYN 	  = #{prdctdateuseyn}
			 , EXPUSEYN  		  = #{expuseyn}
			 , FRUOM			  = #{fruom}
         WHERE
             BRANDKEY = #{brandkey}

mapper.delete:
/* adm-item-brandmanagement-sql-oracle.xml - deleteBrandCode */
DELETE FROM TADMIN_MST_ICXBRAND
WHERE  BRANDKEY = #{brandkey}

mapper.select:
/* adm-item-brandmanagement-sql-oracle.xml - selectBrandCodeInfoExcelDown */ SELECT BRANDKEY , BRANDNM , BRCDLENGTH , CNTRYCD , (SELECT ADCDDTNM FROM TADMIN_MST_ADCD_DT WHERE ADCDHDKEY = 'COUNTRYCODE' AND LAKEY = #{slakey} AND ADCDDTKEY = CNTRYCD) AS COUNTRYNAME , ICLOC , UOMLOC , WEIGHTLOC , DCMLPOINTLOC , PRDCTDATELOC , EXPLOC , ICLENGTH , UOMLENGTH , WEIGHTLENGTH , DCMLPOINTLENGTH , PRDCTDATELENGTH , EXPLENGTH , DCMLPOINT , UOM , UOMNM , DELYN , UOMUSEYN , DCMLPOINTUSEYN , ICUSEYN , WEIGHTUSEYN , PRDCTDATEUSEYN , EXPUSEYN , FRUOM , UOM , INSERTDATE , UPDATEDATE , INSERTURKEY , UPDATEURKEY FROM TADMIN_MST_ICXBRAND
WHERE #{SEARCH_CONDITION}
ORDER BY UPDATEDATE DESC
